package.run:
$ErrorActionPreference = "Stop"
switch ($env:SDKWORK_PACKAGE_PROFILE) {
  'server' {
    New-Item -ItemType Directory -Force -Path artifacts/release | Out-Null
    cargo build --release -p sdkwork-aiot-gateway -p sdkwork-aiot-app-api -p sdkwork-aiot-admin-api
    Copy-Item target/release/sdkwork-aiot-gateway.exe artifacts/release/ -ErrorAction SilentlyContinue
    Copy-Item target/release/sdkwork-aiot-app-api.exe artifacts/release/ -ErrorAction SilentlyContinue
    Copy-Item target/release/sdkwork-aiot-admin-api.exe artifacts/release/ -ErrorAction SilentlyContinue
    Copy-Item target/release/sdkwork-aiot-gateway artifacts/release/ -ErrorAction SilentlyContinue
    Copy-Item target/release/sdkwork-aiot-app-api artifacts/release/ -ErrorAction SilentlyContinue
    Copy-Item target/release/sdkwork-aiot-admin-api artifacts/release/ -ErrorAction SilentlyContinue
  }
  default { Write-Host "Skipping AIoT package archive for profile $($env:SDKWORK_PACKAGE_PROFILE)" }
}

sbom.run:
import { mkdirSync, writeFileSync } from 'node:fs';
import path from 'node:path';
const env = process.env;
const packageId = env.SDKWORK_PACKAGE_ID || env.SDKWORK_PACKAGE_TARGET_ID || 'sdkwork-aiot';
const output = path.posix.join('artifacts/release/sbom', `${packageId}.sbom.json`);
mkdirSync(path.dirname(output), { recursive: true });
writeFileSync(output, `${JSON.stringify({ bomFormat: 'CycloneDX', specVersion: '1.6', version: 1, metadata: { timestamp: new Date().toISOString(), tools: [{ vendor: 'SDKWork', name: 'sdkwork-aiot-workflow-sbom', version: '1.0.0' }], component: { type: 'application', name: env.SDKWORK_APP_ID || 'sdkwork-aiot', version: env.SDKWORK_PACKAGE_VERSION || env.SDKWORK_RELEASE_TAG || '0.1.0', 'bom-ref': packageId }, properties: [{ name: 'sdkwork:packageId', value: packageId }, { name: 'sdkwork:targetId', value: env.SDKWORK_PACKAGE_TARGET_ID || packageId }, { name: 'sdkwork:runtimeTarget', value: env.SDKWORK_RUNTIME_TARGET || 'server' }, { name: 'sdkwork:deploymentProfile', value: env.SDKWORK_DEPLOYMENT_PROFILE || 'standalone' }] }, components: [] }, null, 2)}\n`);
